// triangulation_presets.js — a library of standard ideal triangulations.
//
// Closed-surface fixtures are faithful copies of the repo's
// skein_sphere/triangulation.py class methods (edge-index data verified
// entry-by-entry against Python, incl. sigma() and flip↔mutation).  Polygon
// (disk) charts are generated by `fanPolygon(n)`, reproducing
// BorderedTriangulation.fan_polygon(n) → Triangulation.from_bordered_slots.
//
// A genus-1 example (the Möbius–Kantor / once-punctured-torus-style chart) is
// included so the developed fundamental-polygon-with-identifications view has a
// non-spherical case to show.

import { makeTriangulation } from "./triangulation.js";

// ── The fan triangulation of an n-gon (disk with n boundary marked points) ──
//
// Diagonals (0, d) for d = 2 … n−2 come first (edge ids 0 … n−4); then the n
// boundary sides.  Numbering reproduces fan_polygon(n) exactly, so σ indexing
// and flip-node ids match the Python chart.
export function fanPolygon(n) {
  if (n < 3) throw new Error("a polygon needs n ≥ 3 marked points");
  const edges = [];
  const edgeId = new Map(); // "u,v" -> id
  const put = (u, v) => {
    const key = `${Math.min(u, v)},${Math.max(u, v)}`;
    const id = edges.length;
    edges.push([Math.min(u, v), Math.max(u, v)]);
    edgeId.set(key + `#${id}`, id); // allow the loop below to address by construction
    return id;
  };
  // diagonals (0,2)…(0,n-2) → ids 0 … n-4
  const diagId = new Map();
  for (let d = 2; d <= n - 2; d++) diagId.set(d, put(0, d));
  // boundary sides: (0,1) first, then (i,i+1) for i=1..n-2, then (0,n-1)
  const sideId = new Map();
  sideId.set("0,1", put(0, 1));
  for (let i = 1; i <= n - 2; i++) sideId.set(`${i},${i + 1}`, put(i, i + 1));
  sideId.set(`0,${n - 1}`, put(0, n - 1));

  const eid = (u, v) => {
    if (u === 0 && v >= 2 && v <= n - 2) return diagId.get(v);
    if (v === 0 && u >= 2 && u <= n - 2) return diagId.get(u);
    const a = Math.min(u, v), b = Math.max(u, v);
    if (a === 0 && b === 1) return sideId.get("0,1");
    if (a === 0 && b === n - 1) return sideId.get(`0,${n - 1}`);
    return sideId.get(`${a},${b}`);
  };
  // triangle i (i=0..n-3) on vertices (0, i+1, i+2), edges opposite each corner
  const triangleEdges = [];
  for (let i = 0; i <= n - 3; i++) {
    triangleEdges.push([eid(0, i + 1), eid(i + 1, i + 2), eid(0, i + 2)]);
  }
  return makeTriangulation({
    name: `Polygon P${n}`, nPunctures: n, edges, triangleEdges, kind: "bordered",
  });
}

