// The once-punctured torus (genus 1) = N=2* SU(2): one vertex, three
// self-loop edges, two triangles both reading (0,1,2) ccw.  Faithful to
// skein_annulus_kalg.py's `Triangulation.from_edge_data(1, [(0,0)*3],
// [(0,1,2),(0,1,2)])` (asserted genus 1 there).  Its σ is the Markov quiver
// [[0,2,−2],[−2,0,2],[2,−2,0]].  This is the classic "square with opposite
// sides identified" fundamental polygon, diagonal triangulated — the flagship
// case for the developed identified-sides view.
const TORUS = {
  name: "Once-punctured torus T²₁,₁", nPunctures: 1,
  edges: [[0, 0], [0, 0], [0, 0]],
  triangleEdges: [[0, 1, 2], [0, 1, 2]],
};

// The Csaszar (K₇) ideal triangulation of the 7-punctured torus (genus 1):
// the complete graph K₇ embedded on the torus with all 14 faces triangles,
// faces (i, i+1, i+3) and (i, i+3, i+2) over Z₇.  Verified genus 1 in Python.
function csaszarTorus() {
  const edgeId = new Map();
  const edges = [];
  const eid = (a, b) => {
    const key = `${Math.min(a, b)},${Math.max(a, b)}`;
    if (!edgeId.has(key)) { edgeId.set(key, edges.length); edges.push([Math.min(a, b), Math.max(a, b)]); }
    return edgeId.get(key);
  };
  const tris = [];
  const face = (a, b, c) => tris.push([eid(a, b), eid(b, c), eid(c, a)]);
  for (let i = 0; i < 7; i++) {
    face(i % 7, (i + 1) % 7, (i + 3) % 7);
    face(i % 7, (i + 3) % 7, (i + 2) % 7);
  }
  return makeTriangulation({ name: "Csaszar torus T²₁,₇", nPunctures: 7, edges, triangleEdges: tris, kind: "closed" });
}

// SU(2)+N_f bordered disks (faithful to skein_su2_nf{2,3}_disk).  Their
// boundary components are encoded as self-loop edges (an irregular puncture /
// n-boundary); interior vertices are regular punctures.  Best viewed as the
// dual exchange quiver.
const NF2_DISK = {
  name: "SU(2) N_f=2 disk", nPunctures: 3,
  edges: [[0, 1], [0, 2], [0, 1], [1, 2], [0, 0]],
  triangleEdges: [[0, 3, 1], [1, 3, 2], [2, 0, 4]],
};
const NF3_DISK = {
  name: "SU(2) N_f=3 disk", nPunctures: 4,
  edges: [[0, 2], [1, 2], [0, 3], [1, 3], [2, 3], [0, 1], [0, 1]],
  triangleEdges: [[5, 1, 0], [6, 2, 3], [0, 4, 2], [3, 4, 1]],
};

